{
    "level": "B2–C1",
    "intro": "In this topic you will learn <strong>advanced use of articles</strong> for generalizations - how to talk about a <strong>whole class / category</strong> of objects or people.",
    "rules": [
        {
            "label": "THE + adjective",
            "color": "purple",
            "text": "<strong>The + adjective</strong> = group of people:",
            "example": "the rich, the poor, the young, the elderly"
        },
        {
            "label": "A/AN + singular",
            "color": "blue",
            "text": "<strong>A/An + singular</strong> = the whole species (formal):",
            "example": "A tiger is a dangerous animal."
        },
        {
            "label": "Ø + plural",
            "color": "emerald",
            "text": "<strong>No article + plural</strong> = in general:",
            "example": "Tigers are dangerous. / People need love."
        }
    ]
}

{
    "title": "1. What is a generic reference?",
    "intro": "Generic reference is a generalizing reference to an entire class or category:",
    "items": [
        {
            "label": "THE + adj",
            "title": "A group of people based on the characteristic",
            "subtitle": "the rich, the poor, the blind - all the rich, all the poor"
        },
        {
            "label": "A + singular",
            "title": "Representative of the species",
            "subtitle": "A tiger hunts at night - a tiger (as a species) hunts at night"
        },
        {
            "label": "Ø + plural",
            "title": "All representatives",
            "subtitle": "Tigers hunt at night - tigers (in general) hunt at night"
        }
    ]
}

{
    "title": "2. THE + adjective = group of people",
    "sections": [
        {
            "label": "Basic rule",
            "color": "purple",
            "description": "<strong>The + adjective</strong> means <strong>all people with this feature</strong> (plural).",
            "examples": [
                {
                    "en": "the rich = all rich people",
                    "ua": "all rich people"
                },
                {
                    "en": "the poor = all poor people",
                    "ua": "all poor люди"
                },
                {
                    "en": "the young = all young people",
                    "ua": "all young people"
                },
                {
                    "en": "the elderly = all elderly people",
                    "ua": "all elderly people"
                }
            ]
        },
        {
            "label": "In sentences",
            "color": "blue",
            "description": "Examples of using <strong>the + adjective</strong>:",
            "examples": [
                {
                    "en": "The rich get richer.",
                    "ua": "The rich get richer."
                },
                {
                    "en": "The poor need help.",
                    "ua": "The poor need help."
                },
                {
                    "en": "The young often rebel.",
                    "ua": " rebel."
                },
                {
                    "en": "Society must protect the vulnerable.",
                    "ua": "Society must protect the vulnerable."
                }
            ]
        },
        {
            "label": "Popular examples",
            "color": "sky",
            "description": "Most common constructions:",
            "examples": [
                {
                    "en": "the rich / the poor / the wealthy",
                    "ua": "the young / the old / the elderly"
                },
                {
                    "en": "the young / the old / the elderly",
                    "ua": "the blind / the deaf / the disabled"
                },
                {
                    "en": "the blind / the deaf / the disabled",
                    "ua": " by disability"
                },
                {
                    "en": "the unemployed / the homeless",
                    "ua": "небромы / недомы"
                }
            ],
            "note": "⚠️ The verb is always <strong>plural</strong>: The rich <strong>are</strong> getting richer."
        }
    ]
}

{
    "title": "3. THE + nationality",
    "sections": [
        {
            "label": "Ending -ese, -ss, -sh, -ch",
            "color": "amber",
            "description": "<strong>The + nationality</strong> in -ese, -ss, -sh, -ch = all representatives of the nation.",
            "examples": [
                {
                    "en": "the Chinese = all Chinese people",
                    "ua": "all Chinese people"
                },
                {
                    "en": "the Japanese = all Japanese people",
                    "ua": "all Japanese"
                },
                {
                    "en": "the Swiss = all Swiss people",
                    "ua": "all Swiss"
                },
                {
                    "en": "the British = all British people",
                    "ua": "all Britons"
                },
                {
                    "en": "the French = all French people",
                    "ua": "all French"
                }
            ]
        },
        {
            "label": "U in sentences",
            "color": "purple",
            "description": "Examples of use:",
            "examples": [
                {
                    "en": "The Japanese are known for their politeness.",
                    "ua": "The Japanese are known for their politeness."
                },
                {
                    "en": "The British love tea.",
                    "ua": "The British love tea."
                },
                {
                    "en": "The French value art and culture.",
                    "ua": "The French appreciate art and culture."
                }
            ]
        },
        {
            "label": "Other nationalities",
            "color": "sky",
            "description": "Nationalities with other endings — <strong>without the</strong>, in the plural:",
            "examples": [
                {
                    "en": "Ukrainians (not the Ukrainians)",
                    "ua": "ukrainians"
                },
                {
                    "en": "Americans, Germans, Italians",
                    "ua": "Americans, Germans, Italians"
                }
            ],
            "note": "📌 <strong>The + -ese/-ss/-sh/-ch</strong>, others are just plural."
        }
    ]
}

{
    "title": "4. A/AN + singular = the whole species (formal)",
    "sections": [
        {
            "label": "A species representative",
            "color": "blue",
            "description": "<strong>A/An + singular</strong> can mean <strong>the whole species</strong> (more formally).",
            "examples": [
                {
                    "en": "A tiger is a dangerous animal.",
                    "ua": "Tiger (as a species) is dangerous animal."
                },
                {
                    "en": "A computer can store data.",
                    "ua": "A computer (as a device) can store data."
                },
                {
                    "en": "A dog is loyal to its owner.",
                    "ua": "A dog is (generally) loyal to its owner."
                }
            ]
        },
        {
            "label": "When to use",
            "color": "purple",
            "description": "Used in <strong>definitions, scientific texts, formal descriptions</strong>.",
            "examples": [
                {
                    "en": "A whale is a mammal, not a fish.",
                    "ua": "A whale is a mammal, not a fish."
                },
                {
                    "en": "A triangle has three sides.",
                    "ua": "A triangle has three sides."
                },
                {
                    "en": "An atom consists of protons, neutrons, and electrons.",
                    "ua": "An atom consists of protons, neutrons and electrons."
                }
            ]
        },
        {
            "label": "Comparison with plural",
            "color": "sky",
            "description": "Difference between a/an and plural:",
            "examples": [
                {
                    "en": "A tiger is dangerous. (formal)",
                    "ua": "The tiger is dangerous. (formal)"
                },
                {
                    "en": "Tigers are dangerous. (neutral)",
                    "ua": "Tigers are dangerous. (neutral)"
                }
            ],
            "note": "📌 Both options are correct, but <strong>a/an</strong> is more formal."
        }
    ]
}

{
    "title": "5. Ø + plural = in general (neutral)",
    "sections": [
        {
            "label": "General meaning",
            "color": "emerald",
            "description": "<strong>No article + plural</strong> is the most common method of generalization.",
            "examples": [
                {
                    "en": "Tigers are dangerous.",
                    "ua": "Tigers are dangerous. (all tigers in general)"
                },
                {
                    "en": "People need love.",
                    "ua": "People need love."
                },
                {
                    "en": "Dogs are loyal animals.",
                    "ua": "Dogs are loyal animals."
                },
                {
                    "en": "Books are sources of knowledge.",
                    "ua": "Books are sources knowledge."
                }
            ]
        },
        {
            "label": "The most common option",
            "color": "sky",
            "description": "In colloquial and neutral language, the plural is most often without an article.",
            "examples": [
                {
                    "en": "Computers make life easier.",
                    "ua": "Computers make life easier."
                },
                {
                    "en": "Children need education.",
                    "ua": "Children need education."
                },
                {
                    "en": "Scientists study nature.",
                    "ua": "Scientists study nature."
                }
            ]
        }
    ]
}

{
    "title": "6. THE + singular = the whole species (rare)",
    "sections": [
        {
            "label": "Unique exceptions",
            "color": "rose",
            "description": "<strong>The + singular</strong> is rare, but can mean the whole species (very formal).",
            "examples": [
                {
                    "en": "The tiger is a dangerous animal.",
                    "ua": "The tiger (as a species) is dangerous animal."
                },
                {
                    "en": "The computer has changed our lives.",
                    "ua": "The computer (as an invention) has changed our lives."
                }
            ]
        },
        {
            "label": "When used",
            "color": "amber",
            "description": "Only in <strong>very formal</strong> contexts or historical descriptions.",
            "examples": [
                {
                    "en": "The telephone revolutionized communication.",
                    "ua": "The telephone revolutionized communication."
                },
                {
                    "en": "The dinosaur became extinct millions of years ago.",
                    "ua": "The dinosaur died out millions of years ago."
                }
            ],
            "note": "📌 A rare option is to use the plural or a/an."
        }
    ]
}

{
    "title": "7. Other generalizing constructions",
    "sections": [
        {
            "label": "THE + superlative",
            "color": "purple",
            "description": "<strong>The + highest degree</strong> for generalizations.",
            "examples": [
                {
                    "en": "The best things in life are free.",
                    "ua": "The best things in life are free."
                },
                {
                    "en": "The most important thing is health.",
                    "ua": "The most important thing is health."
                }
            ]
        },
        {
            "label": "THE + only/main/same",
            "color": "blue",
            "description": "З певними прикметниками завжди <strong>the</strong>.",
            "examples": [
                {
                    "en": "The only solution is to try harder.",
                    "ua": "Єдиний вихід — старатися більше."
                },
                {
                    "en": "The main problem is lack of time.",
                    "ua": "The main problem is lack of time."
                },
                {
                    "en": "We have the same opinion.",
                    "ua": "We have the same opinion."
                }
            ]
        }
    ]
}

{
    "title": "8. Comparison table of generalizations",
    "intro": "Different ways of conveying generic reference:",
    "rows": [
        {
            "en": "THE + adjective",
            "ua": "Group of people by characteristic",
            "note": "the rich, the poor, the young (plural meaning)"
        },
        {
            "en": "THE + nationality (-ese/-sh/-ch)",
            "ua": "All representatives of the nation",
            "note": "the Chinese, the British, the French"
        },
        {
            "en": "A/AN + singular",
            "ua": "All species (formal)",
            "note": "A tiger is dangerous. (formal definition)"
        },
        {
            "en": "Ø + plural",
            "ua": "The whole species (neutral)",
            "note": "Tigers are dangerous. (most common)"
        },
        {
            "en": "THE + singular",
            "ua": "The whole species (very formal)",
            "note": "The tiger is dangerous. (rare, very formal)"
        }
    ],
    "warning": "📌 The most common variant is <strong>plural without article</strong>. <strong>A/an + singular</strong> is formal. <strong>The + singular</strong> is rare."
}

{
    "title": "9. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Singular verb with the + adjective.",
            "wrong": "The rich is getting richer.[[[CODX_30]]]​​​​ <span class="font-mono">The rich are getting richer. (plural!)</span>",
            "right": "✅ <span class="font-mono">The rich are getting richer. (plural!)</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "The before the usual nationality.",
            "wrong": "The Ukrainians are friendly.",
            "right": "​​​​ <span class="font-mono">Ukrainians are friendly. (without the)</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "The article in a general statement.",
            "wrong": "The tigers are dangerous. (all tigers in general)",
            "right": "​​​​ <span class="font-mono">Tigers are dangerous. (without the)</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Wrong choice of form.",
            "wrong": "Tiger is dangerous. (without singular article)",
            "right": "​​​​ <span class="font-mono">A tiger is dangerous. / Tigers are dangerous.</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose the correct form for generalization.",
    "selects": [
        {
            "label": "___ need education. (The children / Children)",
            "prompt": "Which option?"
        },
        {
            "label": "___ are getting richer. (The rich / Rich)",
            "prompt": "Which option?"
        },
        {
            "label": "___ is a dangerous animal. (Tiger / A tiger)",
            "prompt": "Which option?"
        },
        {
            "label": "___ are known for politeness. (Japanese / The Japanese)",
            "prompt": "Which option?"
        }
    ],
    "options": [
        "First option",
        "Second option"
    ],
    "input_title": "Exercise 2. Fill in the blanks",
    "input_intro": "Write the correct form (the, a, or Ø).",
    "inputs": [
        {
            "before": "___ poor need help.",
            "after": "→"
        },
        {
            "before": "___ computer has changed our lives.",
            "after": "→"
        },
        {
            "before": "___ dogs are loyal animals.",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correct errors",
    "rephrase_intro": "Find and correct the mistake in the sentence.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "The rich is getting richer.",
            "example_target": "The rich are getting richer."
        },
        {
            "original": "1. The tigers are dangerous animals. (general statement)",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. Ukrainians are friendly people. Articles",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Іменники, артиклі та кількість",
    "items": [
        {
            "label": "Advanced articles — узагальнення (поточна)",
            "current": true
        },
        {
            "label": "Articles with geographical names",
            "current": false
        },
        {
            "label": "Articles A / An / The — Артиклі",
            "current": false
        },
        {
            "label": "Zero Article — Zero article",
            "current": false
        }
    ]
}
